class Solution {
    public boolean canConvertString(String s, String t, int k) {
        int n = s.length();
        int[] cnt = new int[26];
        for (int i = 0; i < n; i++) {
            int diff = (t.charAt(i) - s.charAt(i) + 26) % 26;
            cnt[diff]++;
        }
        for (int i = 1; i < 26; i++) {
            if (cnt[i] > 0 && cnt[i] > (k / i)) {
                return false;
            }
        }
        return true;
    }
}
